func caesar(s string, shift int) string {
	shift = ((shift % 26) + 26) % 26 // normalize to 0..25
	out := []rune(s)
	for i, r := range out {
		switch {
		case r >= 'a' && r <= 'z':
			out[i] = 'a' + (r-'a'+rune(shift))%26
		case r >= 'A' && r <= 'Z':
			out[i] = 'A' + (r-'A'+rune(shift))%26
		}
	}
	return string(out)
}

func main() {
	enc := caesar("Hello, World!", 3)
	fmt.Println("encoded:", enc)
	fmt.Println("decoded:", caesar(enc, -3))
}
```

